local prefix = "                " 
local fullText = "phantom.bin - discord.gg/8h9hDgbzUV"
local currentIndex = 0
local isTyping = true
local textUpdateTimer = 0

local textUpdateDelay = 0.05
local pauseDuration = 1

local TitleAnimConn
TitleAnimConn = RunService.Heartbeat:Connect(function(dt)
    if Library.Unloaded then
        TitleAnimConn:Disconnect()
        return
    end

    textUpdateTimer = textUpdateTimer + dt
    if textUpdateTimer >= textUpdateDelay then
        textUpdateTimer = 0
        
        if isTyping then
            currentIndex = currentIndex + 1
            if currentIndex >= #fullText then
                currentIndex = #fullText
                isTyping = false
                textUpdateTimer = -pauseDuration
            end
        else
            currentIndex = currentIndex - 1
            if currentIndex <= 0 then
                currentIndex = 0
                isTyping = true
                textUpdateTimer = -(pauseDuration / 2)
            end
        end
        
        local currentText = string.sub(fullText, 1, currentIndex)
        local hex = "FFFFFF"
        if Options.AccentColor then
            hex = Options.AccentColor.Value:ToHex()
        end
        
        Window:SetWindowTitle(prefix .. '<font color="#' .. hex .. '">' .. currentText .. '</font>')
    end
end)

local SKIN_ENABLED = false
local skinConnection = nil
local originalSkinBackup = nil
_G.SELECTED_SKIN = '62536494'

local function saveOriginalSkin()
    local char = LocalPlayer.Character
    if not char then return end
    local head = char:WaitForChild("Head", 10)
    if not head then return end

    originalSkinBackup = {
        accessories = {},
        shirt = nil,
        pants = nil,
        bodyColors = nil,
        face = nil,
        headMesh = nil,
    }

    for _, v in pairs(char:GetChildren()) do
        if v.Name == "ToxicHorns_Persistent" then continue end
        if v:IsA("Accessory") then
            table.insert(originalSkinBackup.accessories, v:Clone())
        elseif v:IsA("Shirt") then
            originalSkinBackup.shirt = v:Clone()
        elseif v:IsA("Pants") then
            originalSkinBackup.pants = v:Clone()
        elseif v:IsA("BodyColors") then
            originalSkinBackup.bodyColors = v:Clone()
        end
    end

    local face = head:FindFirstChild("face")
    if face then
        originalSkinBackup.face = face:Clone()
    end

    local mesh = head:FindFirstChildOfClass("SpecialMesh")
    if mesh then
        originalSkinBackup.headMesh = mesh:Clone()
    end
end

local function restoreOriginalSkin()
    if not originalSkinBackup then return end
    
    local char = LocalPlayer.Character
    if not char then return end
    local head = char:WaitForChild("Head", 10)
    if not head then return end

    for _, v in pairs(char:GetChildren()) do
        if v.Name == "ToxicHorns_Persistent" then continue end
        if v:IsA("Accessory") or v:IsA("Shirt") or v:IsA("Pants") or v:IsA("BodyColors") then
            v:Destroy()
        end
    end
    if head:FindFirstChild("face") then head.face:Destroy() end

    for _, acc in pairs(originalSkinBackup.accessories) do
        local newAcc = acc:Clone()
        newAcc.Parent = char
        local handle = newAcc:FindFirstChild("Handle")
        if handle then
            handle.CanCollide = false
            local att = handle:FindFirstChildOfClass("Attachment")
            if att then
                local targetAtt = char:FindFirstChild(att.Name, true)
                if targetAtt then
                    handle.CFrame = targetAtt.WorldCFrame * att.CFrame:Inverse()
                    local w = Instance.new("WeldConstraint")
                    w.Part0 = handle
                    w.Part1 = targetAtt.Parent
                    w.Parent = handle
                end
            end
        end
    end

    if originalSkinBackup.shirt then originalSkinBackup.shirt:Clone().Parent = char end
    if originalSkinBackup.pants then originalSkinBackup.pants:Clone().Parent = char end
    if originalSkinBackup.bodyColors then originalSkinBackup.bodyColors:Clone().Parent = char end

    if originalSkinBackup.face then
        local newFace = originalSkinBackup.face:Clone()
        newFace.Parent = head
    end

    if originalSkinBackup.headMesh then
        local existingMesh = head:FindFirstChildOfClass("SpecialMesh")
        if existingMesh then existingMesh:Destroy() end
        originalSkinBackup.headMesh:Clone().Parent = head
    end

    originalSkinBackup = nil
end

_G.applySkin = function(targetId)
    local char = LocalPlayer.Character
    if not char then return end
    local head = char:WaitForChild("Head", 10)
    if not head then return end

    local idNum = tonumber(targetId)
    if not idNum then 
        Library:Notify("Invalid User ID!", 3)
        return 
    end

    for _, v in pairs(char:GetChildren()) do
        if v.Name == "ToxicHorns_Persistent" then continue end
        if v:IsA("Accessory") or v:IsA("Shirt") or v:IsA("Pants") or v:IsA("BodyColors") then
            v:Destroy()
        end
    end
    if head:FindFirstChild("face") then head.face:Destroy() end

    local success, err = pcall(function()
        local appearance = Players:GetCharacterAppearanceAsync(idNum)
        for _, item in pairs(appearance:GetChildren()) do
            if item:IsA("Shirt") or item:IsA("Pants") or item:IsA("BodyColors") then
                item.Parent = char
            elseif item:IsA("Accessory") then
                task.spawn(function()
                    local newItem = item:Clone()
                    newItem.Parent = char
                    local handle = newItem:FindFirstChild("Handle")
                    if handle then
                        handle.CanCollide = false
                        local att = handle:FindFirstChildOfClass("Attachment")
                        if att then
                            local targetAtt = char:FindFirstChild(att.Name, true)
                            if targetAtt then
                                handle.CFrame = targetAtt.WorldCFrame * att.CFrame:Inverse()
                                local w = Instance.new("WeldConstraint")
                                w.Part0 = handle
                                w.Part1 = targetAtt.Parent
                                w.Parent = handle
                            end
                        end
                    end
                end)
            elseif item:IsA("Decal") and (item.Name == "face" or item.Texture:find("rbxassetid")) then
                item.Name = "face"
                item.Parent = head
            elseif item:IsA("SpecialMesh") and item.MeshType == Enum.MeshType.Head then
                local myMesh = head:FindFirstChildOfClass("SpecialMesh") or Instance.new("SpecialMesh", head)
                myMesh.MeshId = item.MeshId
                myMesh.TextureId = item.TextureId
                myMesh.Scale = item.Scale
            end
        end
    end)
    
    if not success then
        Library:Notify("Failed to load skin. ID might be wrong or rate limited.", 3)
    end
end

Toggles.SkinToggle:OnChanged(function()
    SKIN_ENABLED = Toggles.SkinToggle.Value
    if SKIN_ENABLED then
        saveOriginalSkin()
        _G.applySkin(_G.SELECTED_SKIN)
        if skinConnection then skinConnection:Disconnect() end
        skinConnection = LocalPlayer.CharacterAdded:Connect(function(char)
            char:WaitForChild("HumanoidRootPart")
            char:WaitForChild("Head")
            char:WaitForChild("Humanoid")
            local humanoid = char:FindFirstChildOfClass("Humanoid")
            if humanoid then
                repeat task.wait() until humanoid:GetState() ~= Enum.HumanoidStateType.None
            end
            task.wait(0.5)
            if SKIN_ENABLED and char.Parent then
                saveOriginalSkin()
                _G.applySkin(_G.SELECTED_SKIN)
            end
        end)
    else
        restoreOriginalSkin()
        if skinConnection then
            skinConnection:Disconnect()
            skinConnection = nil
        end
    end
end)


local HideFloorPart = nil
local OriginalY = nil

Toggles.HideFloor:OnChanged(function()
    local char = LocalPlayer.Character
    local hrp = char and char:FindFirstChild("HumanoidRootPart")
    
    if Toggles.HideFloor.Value then
        if hrp then
            OriginalY = hrp.Position.Y
            local depth = Options.HideFloorDepth.Value
            hrp.CFrame = hrp.CFrame * CFrame.new(0, -depth, 0)
            
            if not HideFloorPart then
                HideFloorPart = Instance.new("Part")
                HideFloorPart.Name = "PhantomHideFloor"
                HideFloorPart.Size = Vector3.new(2048, 5, 2048)
                HideFloorPart.Anchored = true
                HideFloorPart.CanCollide = true
                HideFloorPart.Transparency = 1
                HideFloorPart.Parent = Workspace
            end
            HideFloorPart.Position = hrp.Position - Vector3.new(0, 5.5, 0)
        else
            Toggles.HideFloor:SetValue(false)
        end
    else
        if hrp and OriginalY then
            hrp.CFrame = CFrame.new(hrp.Position.X, OriginalY, hrp.Position.Z) * (hrp.CFrame - hrp.CFrame.Position)
        end
        if HideFloorPart then
            HideFloorPart:Destroy()
            HideFloorPart = nil
        end
        OriginalY = nil
    end
end)

Options.HideFloorDepth:OnChanged(function()
    if Toggles.HideFloor.Value then
        local char = LocalPlayer.Character
        local hrp = char and char:FindFirstChild("HumanoidRootPart")
        if hrp and OriginalY then
            hrp.CFrame = CFrame.new(hrp.Position.X, OriginalY - Options.HideFloorDepth.Value, hrp.Position.Z) * (hrp.CFrame - hrp.CFrame.Position)
            if HideFloorPart then
                HideFloorPart.Position = hrp.Position - Vector3.new(0, 5.5, 0)
            end
        end
    end
end)

local function checkRageTargetNear()
    if not Toggles.Ragebot.Value then return false end
    if not LocalPlayer.Team then return false end
    
    local currentCam = workspace.CurrentCamera
    local shortestDistance = Options.RageDist.Value
    local myTeamName = LocalPlayer.Team.Name
    local char = LocalPlayer.Character
    if not char or not char:FindFirstChild("Head") then return false end
    local headPos = char.Head.Position
    local mouseLoc = GetCenterOrMouse()
    
    for _, player in pairs(Players:GetPlayers()) do
        if player ~= LocalPlayer then
            local tChar = player.Character
            if tChar and tChar:FindFirstChild("Torso") and tChar:FindFirstChild("Humanoid") and tChar.Humanoid.Health > 0 then
                if player.Team then
                    local tTeam = player.Team.Name
                    local isTarget = false
                    if myTeamName == "Criminals" then if tTeam == "Guards" then isTarget = true end
                    elseif myTeamName == "Inmates" then if tTeam == "Guards" or tTeam == "Criminals" then isTarget = true end
                    elseif myTeamName == "Guards" then if tTeam == "Criminals" then isTarget = true end end
                    if not isTarget and tTeam == "Inmates" and string.find(tChar.Humanoid.DisplayName, "💢") then isTarget = true end
                    
                    if isTarget then
                        local tPart = tChar.Torso
                        local dist = (tPart.Position - headPos).Magnitude
                        if dist <= shortestDistance then
                            local isWithinFOV = true
                            if Toggles.RageFOV and Toggles.RageFOV.Value then
                                local screenPos, onScreen = currentCam:WorldToViewportPoint(tPart.Position)
                                if onScreen then
                                    local mouseDist = (Vector2.new(screenPos.X, screenPos.Y) - mouseLoc).Magnitude
                                    if mouseDist > Options.RageFOVRadius.Value then
                                        isWithinFOV = false
                                    end
                                else
                                    isWithinFOV = false
                                end
                            end
                            
                            if isWithinFOV then
                                local hasForceField = tChar:FindFirstChildOfClass("ForceField") ~= nil
                                if not hasForceField or not Toggles.ForceFieldCheck.Value then
                                    local rp = RaycastParams.new()
                                    rp.FilterDescendantsInstances = {char, tChar}
                                    rp.FilterType = Enum.RaycastFilterType.Exclude
                                    if workspace:Raycast(headPos, tPart.Position - headPos, rp) == nil then
                                        return true 
                                    end
                                end
                            end
                        end
                    end
                end
            end
        end
    end
    return false
end

local RealCFrameForHide = nil
local AutoHideFloorPart = nil
local IsTargetNear = false

RunService:BindToRenderStep("AutoHideRestore", Enum.RenderPriority.First.Value, function()
    if Toggles.AutoHide and Toggles.AutoHide.Value and not IsTargetNear then
        local char = LocalPlayer.Character
