        end
    end
end)

local ITEM_ID_HORNS = 1744060292

local function UpdateHornsTransform()
    local char = LocalPlayer.Character
    if char and char:FindFirstChild("ToxicHorns_Persistent") then
        local acc = char["ToxicHorns_Persistent"]
        local handle = acc:FindFirstChildWhichIsA("BasePart") or acc:FindFirstChild("Handle")
        if handle then
            local weld = handle:FindFirstChildWhichIsA("Weld")
            if weld then
                weld.C0 = CFrame.new(Options.HornsOffsetX.Value, Options.HornsOffsetY.Value, Options.HornsOffsetZ.Value)
            end
            
            local mesh = handle:FindFirstChildWhichIsA("SpecialMesh")
            if mesh then
                if not mesh:GetAttribute("OriginalScale") then
                    mesh:SetAttribute("OriginalScale", mesh.Scale)
                end
                local origScale = mesh:GetAttribute("OriginalScale")
                mesh.Scale = origScale * Options.HornsScale.Value
            else
                if not handle:GetAttribute("OriginalSize") then
                    handle:SetAttribute("OriginalSize", handle.Size)
                end
                handle.Size = handle:GetAttribute("OriginalSize") * Options.HornsScale.Value
            end
        end
    end
end

local function EquipHorns()
    local character = LocalPlayer.Character
    if not character then return end
    local head = character:WaitForChild("Head", 3)
    if not head then return end
    
    if character:FindFirstChild("ToxicHorns_Persistent") then
        character["ToxicHorns_Persistent"]:Destroy()
    end

    if not Toggles.EnableToxicHorns.Value then return end

    task.spawn(function()
        local success, assets = pcall(function()
            return game:GetObjects("rbxassetid://" .. ITEM_ID_HORNS)
        end)

        if success and assets and assets[1] then
            local accessory = assets[1]
            accessory.Name = "ToxicHorns_Persistent"
            accessory.Parent = character

            local handle = accessory:FindFirstChildWhichIsA("BasePart") or accessory:FindFirstChild("Handle")
            if handle then
                local weld = Instance.new("Weld")
                weld.Name = "HornsWeld"
                weld.Part0 = handle
                weld.Part1 = head
                weld.C0 = CFrame.new(Options.HornsOffsetX.Value, Options.HornsOffsetY.Value, Options.HornsOffsetZ.Value) 
                weld.Parent = handle
                
                local mesh = handle:FindFirstChildWhichIsA("SpecialMesh")
                if mesh then
                    if not mesh:GetAttribute("OriginalScale") then
                        mesh:SetAttribute("OriginalScale", mesh.Scale)
                    end
                    local origScale = mesh:GetAttribute("OriginalScale")
                    mesh.Scale = origScale * Options.HornsScale.Value
                else
                    if not handle:GetAttribute("OriginalSize") then
                        handle:SetAttribute("OriginalSize", handle.Size)
                    end
                    handle.Size = handle:GetAttribute("OriginalSize") * Options.HornsScale.Value
                end
            end
        end
    end)
end

Toggles.EnableToxicHorns:OnChanged(function()
    if Toggles.EnableToxicHorns.Value then
        EquipHorns()
    else
        local char = LocalPlayer.Character
        if char and char:FindFirstChild("ToxicHorns_Persistent") then
            char["ToxicHorns_Persistent"]:Destroy()
        end
    end
