local TracerTemplate = Instance.new("Part"); TracerTemplate.Anchored = true; TracerTemplate.CanCollide = false; TracerTemplate.CanQuery = false; TracerTemplate.Material = Enum.Material.Neon; TracerTemplate.Transparency = 0.3
local function DrawTracer_Optimized(s, e)
    local v = e - s; local d = v.Magnitude; if d < 0.1 then return end
    local width = Options.TracerWidth.Value; local lengthScale = Options.TracerLengthScale.Value; local finalLength = d * lengthScale
    local dir = v.Unit; local centerPos = e - dir * (finalLength / 2)
    local lifeTime = Options.TracerLifeTime.Value
    local mode = Options.TracerMode and Options.TracerMode.Value or '3D Part'
    local color = Options.TracerColor.Value

    if mode == '3D Part' or mode == '3D Highlight' then
        local t = TracerTemplate:Clone()
        t.Size = Vector3.new(width, width, finalLength)
        t.CFrame = CFrame.lookAt(centerPos, e)
        t.Color = color
        t.Parent = Camera

        if mode == '3D Highlight' then
            t.Transparency = 1
            local hl = Instance.new("Highlight")
            hl.Adornee = t
            hl.FillColor = color
            hl.FillTransparency = 0.3
            hl.OutlineTransparency = 1
            hl.DepthMode = Enum.HighlightDepthMode.AlwaysOnTop
            hl.Parent = t
        end
        
        task.delay(lifeTime, function()
            if t then t:Destroy() end
        end)
    elseif mode == '2D Line' then
        local line = Drawing.new("Line")
        line.Color = color
        line.Thickness = math.clamp(width * 50, 1, 5)
        line.Transparency = 1
        
        local startTime = tick()
        local conn
        conn = RunService.RenderStepped:Connect(function()
            local elapsed = tick() - startTime
            if elapsed > lifeTime then
                line.Visible = false
                line:Remove()
                conn:Disconnect()
                return
            end
            local sPos, sVis = Camera:WorldToViewportPoint(s)
            local ePos, eVis = Camera:WorldToViewportPoint(e)
            if sPos.Z > 0 and ePos.Z > 0 then
                line.From = Vector2.new(sPos.X, sPos.Y)
                line.To = Vector2.new(ePos.X, ePos.Y)
                line.Visible = true
            else
                line.Visible = false
            end
        end)
    end
end

local SoundIDs = { ["Neverlose"] = "rbxassetid://8679627751", ["Rust"] = "rbxassetid://4764109000", ["Minecraft Damage"] = "rbxassetid://8766809464", ["Hitmarker"] = "rbxassetid://160432334", ["gamesense"] = "rbxassetid://108447882863330", ["sparkle"] = "rbxassetid://110241936966089" }
local function playSound()
    local idVal = Options.HitSoundId.Value
    local volVal = Options.HitSoundVol.Value
    local s = Instance.new("Sound"); s.SoundId = SoundIDs[idVal] or SoundIDs["Neverlose"]; s.Volume = volVal; s.Parent = SoundService; s:Play()
    task.spawn(function() s.Ended:Wait(); s:Destroy() end)
end

local function ExtractPartsFromData(data, foundParts)
    if type(data) == "table" then
        for _, v in pairs(data) do
            if typeof(v) == "Instance" and v:IsA("BasePart") then
                table.insert(foundParts, v)
            elseif type(v) == "table" then
                ExtractPartsFromData(v, foundParts)
            end
        end
    end
end

local targetCooldowns = {}
local VISUAL_COOLDOWN = 0.05 

local mt = getrawmetatable(game)
local oldNamecall = mt.__namecall
setreadonly(mt, false)

mt.__namecall = newcclosure(function(self, ...)
    local method = getnamecallmethod()
    local args = {...}

    if tostring(self) == "ShootEvent" and method == "FireServer" then
        task.spawn(function()
            
            pcall(function()
                if Toggles.BulletTracers and Toggles.BulletTracers.Value then
                    local bullets = args[1]
                    if type(bullets) == "table" then
                        local lastBullet = bullets[#bullets]
                        if type(lastBullet) == "table" and typeof(lastBullet[1]) == "Vector3" and typeof(lastBullet[2]) == "Vector3" then
                            local startPos = lastBullet[1]
                            local hitPos = lastBullet[2]
                            local char = LocalPlayer.Character
                            if char then
                                local tool = char:FindFirstChildOfClass("Tool")
                                if tool and tool:FindFirstChild("Muzzle") then
                                    startPos = tool.Muzzle.Position
                                end
                            end
                            DrawTracer_Optimized(startPos, hitPos)
                        elseif typeof(bullets[1]) == "Vector3" and typeof(bullets[2]) == "Vector3" then
                            local startPos = bullets[1]
                            local hitPos = bullets[2]
                            local char = LocalPlayer.Character
                            if char then
                                local tool = char:FindFirstChildOfClass("Tool")
                                if tool and tool:FindFirstChild("Muzzle") then
                                    startPos = tool.Muzzle.Position
                                end
                            end
                            DrawTracer_Optimized(startPos, hitPos)
                        end
                    end
                end
            end)

            pcall(function()
                local hitParts = {}
                ExtractPartsFromData(args, hitParts)
                local hitPlayers = {}
                
                for _, tPart in pairs(hitParts) do
                    local char = tPart.Parent
                    if char:IsA("Accessory") then char = char.Parent end
                    local p = Players:GetPlayerFromCharacter(char)
                    
                    if p and p ~= LocalPlayer and not hitPlayers[p] then
                        hitPlayers[p] = true
                        if Toggles.HitSound and Toggles.HitSound.Value then playSound() end
                        if Toggles.HitLog and Toggles.HitLog.Value then 
                            Library:Notify(string.format("Hit %s", p.DisplayName), Options.HitLogDuration.Value) 
                        end
                    end
                end
            end)

            pcall(function()
                if Toggles.EnableHitEffect and Toggles.EnableHitEffect.Value then
                    local hitParts = {}
                    ExtractPartsFromData(args, hitParts)
                    
                    local WeaponDamages = { ["M9"] = 15, ["MP5"] = 11, ["Remington 870"] = 95, ["M4A1"] = 17, ["Revolver"] = 26, ["M700"] = 75, ["AK-47"] = 15, ["FAL"] = 19, ["Taser"] = 0 }
                    local currentDamage = 15
                    local char = LocalPlayer.Character
                    if char then
                        local tool = char:FindFirstChildOfClass("Tool")
                        if tool and WeaponDamages[tool.Name] then
                            currentDamage = WeaponDamages[tool.Name]
                        end
                    end

                    for _, targetPart in pairs(hitParts) do
                        local finalTarget = nil
                        local partName = targetPart.Name

                        if partName == "Head" or partName == "HumanoidRootPart" then
                            finalTarget = targetPart
                        else
                            local tchar = targetPart.Parent
                            if tchar:IsA("Accessory") then tchar = tchar.Parent end
                            if tchar then
                                finalTarget = tchar:FindFirstChild("HumanoidRootPart") 
                                           or tchar:FindFirstChild("UpperTorso")
                                           or tchar:FindFirstChild("Torso")
                            end
                        end

                        if finalTarget then
                            local now = tick()
                            if not targetCooldowns[finalTarget] or (now - targetCooldowns[finalTarget]) >= VISUAL_COOLDOWN then
                                targetCooldowns[finalTarget] = now
                                SpawnPerfectJuiceDamage(currentDamage, finalTarget)
                            end
                        end
                    end
                end
            end)

        end)
    elseif method == "InvokeServer" and tostring(self) == "FuncReload" then
        _G.RageShotsFired = 0
    end
    
    return oldNamecall(self, ...)
end)
setreadonly(mt, true)

local currentAimTarget = nil
local targetAcquiredTime = 0
local currentTriggerTarget = nil
local triggerFocusTime = 0
local isTriggerCooldown = false

RunService:BindToRenderStep("PhantomOverlay", Enum.RenderPriority.Last.Value + 200, function(deltaTime)
    local currentCam = workspace.CurrentCamera
    local mouseLoc = GetCenterOrMouse()

    FOVRegion.Visible = Toggles.ShowFOV.Value
    FOVRegion.Radius = Options.FOVRadius.Value
    FOVRegion.Position = mouseLoc
    FOVRegion.Color = Options.FOVColor.Value

    if Toggles.Aimbot.Value then
        local canAim = (Options.AimbotKey.Value == 'None') or Options.AimbotKey:GetState()
        
        if canAim then
            local t = getClosestPlayer()
            if t and t.Character and t.Character:FindFirstChild("HumanoidRootPart") then
                if currentAimTarget ~= t then
                    currentAimTarget = t
                    targetAcquiredTime = tick()
                end
                local reactionTime = Options.AimReaction.Value / 1000
                if tick() - targetAcquiredTime >= reactionTime then
                    local targetCFrame = CFrame.lookAt(currentCam.CFrame.Position, t.Character.HumanoidRootPart.Position)
                    local speed = Options.AimSpeed.Value / 100
                    local smooth = Options.AimSmoothness.Value
                    local alpha = math.clamp(speed / smooth, 0.01, 1)
                    currentCam.CFrame = currentCam.CFrame:Lerp(targetCFrame, alpha)
                end
            else
                currentAimTarget = nil
            end
        else
            currentAimTarget = nil
        end
    else
        currentAimTarget = nil
    end

    if Toggles.Triggerbot.Value and Options.TriggerbotKey:GetState() then
        local part = GetCenterTarget()
        if isTriggerEnemyTarget(part) then
            if currentTriggerTarget == part then
                triggerFocusTime = triggerFocusTime + deltaTime
                local reaction = Options.TriggerReaction.Value / 1000
                if triggerFocusTime >= reaction and not isTriggerCooldown then
                    isTriggerCooldown = true
                    if mouse1click then
                        mouse1click()
                    elseif mouse1press then
                        mouse1press()
                        task.wait()
                        mouse1release()
                    else
                        VirtualUser:ClickButton1(Vector2.new(0, 0))
                    end
                    task.delay(0.05, function() isTriggerCooldown = false end)
                    triggerFocusTime = 0
                end
            else
                currentTriggerTarget = part
                triggerFocusTime = 0
            end
        else
            currentTriggerTarget = nil
            triggerFocusTime = 0
        end
    else
        currentTriggerTarget = nil
            triggerFocusTime = 0
    end
    
    UpdateESP()

    if Toggles.ShowRageFOV and Toggles.ShowRageFOV.Value then
        RageFOVGui.Enabled = true
        local radius = Options.RageFOVRadius.Value
        RageFOVCircle.Size = UDim2.new(0, radius * 2, 0, radius * 2)
        RageFOVCircle.Position = UDim2.new(0, mouseLoc.X, 0, mouseLoc.Y)
        
        RageFOVStroke.Color = Options.RageFOVColor.Value
        RageFOVCircle.BackgroundColor3 = Options.RageFOVFillColor.Value
        RageFOVCircle.Rotation = (RageFOVCircle.Rotation + 45 * deltaTime) % 360
        
        if Toggles.RageFOVFill.Value then
            RageFOVCircle.BackgroundTransparency = 0
        else
            RageFOVCircle.BackgroundTransparency = 1
        end
    else
        RageFOVGui.Enabled = false
    end

    if Toggles.TimeChanger.Value then 
        local timeVal = Options.TimeVal.Value
        Lighting.ClockTime = timeVal
        
        local sunIntensity = math.clamp(math.sin(math.pi * (timeVal - 6) / 12), 0, 1)
        Lighting.Brightness = 0.5 + (sunIntensity * 2.5) 

        if not Toggles.WorldVisuals.Value then
            local amb = 30 + (sunIntensity * 120) 
            Lighting.Ambient = Color3.fromRGB(amb, amb, amb)
            Lighting.OutdoorAmbient = Color3.fromRGB(amb, amb, amb)
        end
    end

    if Toggles.WorldVisuals.Value then
        local c = Options.WorldColor.Value
        Lighting.Ambient = c; Lighting.OutdoorAmbient = c; Lighting.ColorShift_Top = Color3.fromRGB(180, 120, 255)
        Lighting.FogColor = c; Lighting.FogStart = 0; Lighting.FogEnd = Options.FogDist.Value
        local cc = Lighting:FindFirstChild("PhantomCC") or Instance.new("ColorCorrectionEffect", Lighting)
        cc.Name = "PhantomCC"; cc.Enabled = true; cc.TintColor = c; cc.Saturation = 0.5; cc.Contrast = 0.1
    else
        local cc = Lighting:FindFirstChild("PhantomCC"); if cc then cc.Enabled = false end
    end

    if Toggles.EnableAtmosphere.Value then
        local atmo = Lighting:FindFirstChildOfClass("Atmosphere") or Instance.new("Atmosphere", Lighting)
        atmo.Name = "PhantomAtmosphere"
        local color = Options.AtmosphereColor.Value
        atmo.Color = color
        atmo.Decay = Color3.new(math.clamp(color.R - 0.15, 0, 1), math.clamp(color.G - 0.15, 0, 1), math.clamp(color.B - 0.15, 0, 1))
        atmo.Density = Options.AtmosphereDensity.Value
        atmo.Haze = Options.AtmosphereHaze.Value
        atmo.Glare = 0.5
        atmo.Offset = 0.25
    else
        local atmo = Lighting:FindFirstChild("PhantomAtmosphere")
        if atmo then atmo:Destroy() end
    end

    if Toggles.ResStretch.Value then currentCam.CFrame = currentCam.CFrame * CFrame.new(0, 0, 0, 1, 0, 0, 0, Options.ResFactor.Value, 0, 0, 0, 1) end

    if Toggles.CrosshairEnabled.Value then
        CH_ScreenGui.Enabled = true
        UserInputService.MouseIconEnabled = false 
        
        local basePos = mouseLoc
        
        if Toggles.CrosshairOnMuzzle and Toggles.CrosshairOnMuzzle.Value then
            local char = LocalPlayer.Character
            if char then
                local tool = char:FindFirstChildOfClass("Tool")
                if tool then
                    local muzzle = tool:FindFirstChild("Muzzle")
                    if muzzle then
                        local screenPos, onScreen = currentCam:WorldToViewportPoint(muzzle.Position)
                        if onScreen then
                            basePos = Vector2.new(screenPos.X, screenPos.Y)
                        end
                    end
                end
            end
        end

        local customTextSize = Options.CH_TextSize.Value
        local customTextOffset = Options.CH_TextOffset.Value

        CH_TextLabel.TextSize = customTextSize
        CH_AmmoLabel.TextSize = customTextSize

        CH_Holder.Position = UDim2.fromOffset(basePos.X, basePos.Y)
        CH_TextLabel.Position = UDim2.fromOffset(basePos.X, basePos.Y + customTextOffset)
        
        local textVisible = false
        if Toggles.HideCrosshairText.Value and not Toggles.CrosshairRageInfo.Value then
            CH_TextLabel.Visible = false
        else
            CH_TextLabel.Visible = true
            textVisible = true
            if Toggles.CrosshairRageInfo.Value then
                local rColor = getRichColor(Options.RageInfoColor.Value)
                local wColor = "rgb(255, 255, 255)"
                local displayStatus = RagebotStatus
                
                if not (Toggles.HideFloor.Value or Toggles.AutoHide.Value) and displayStatus == "hiding..." then
                    displayStatus = "not found..."
                end
                
                CH_TextLabel.Text = string.format('<font color="%s">ragebot: </font><font color="%s">%s</font>', rColor, wColor, displayStatus)
            else
                local col1 = getRichColor(Options.CH_TextColor1.Value)
                local col2 = getRichColor(Options.CH_TextColor2.Value)
                CH_TextLabel.Text = string.format('<font color="%s">phantom</font><font color="%s">.bin</font>', col1, col2)
            end
        end

        if Toggles.CrosshairAmmoInfo.Value then
            local curAmmo, mAmmo = getAmmoInfo()
            if curAmmo and mAmmo then
                CH_AmmoLabel.Visible = true
                local aColor = getRichColor(Options.AmmoInfoColor.Value)
                CH_AmmoLabel.Text = string.format('<font color="%s">%d/%d/inf</font>', aColor, curAmmo, mAmmo)
                
                local yOffset = customTextOffset
                if textVisible then yOffset = yOffset + customTextSize + 2 end 
                CH_AmmoLabel.Position = UDim2.fromOffset(basePos.X, basePos.Y + yOffset)
            else
                CH_AmmoLabel.Visible = false
            end
        else
            CH_AmmoLabel.Visible = false
        end
        
        local barColor = Options.CH_BarColor.Value
        local outColor = Options.CH_OutlineColor.Value
        CH_TextStroke.Color = outColor
        CH_AmmoStroke.Color = outColor
        
        CH_Top.BackgroundColor3 = barColor; CH_Top.Outline.Color = outColor
        CH_Bottom.BackgroundColor3 = barColor; CH_Bottom.Outline.Color = outColor
        CH_Left.BackgroundColor3 = barColor; CH_Left.Outline.Color = outColor
        CH_Right.BackgroundColor3 = barColor; CH_Right.Outline.Color = outColor
        
        local g = Options.CH_Gap.Value; local maxLen = Options.CH_Length.Value
        local ct = os.clock(); local alpha = (ct % CH_Config.CycleDuration) / CH_Config.CycleDuration
        local currentRotation = easeHybrid(alpha) * 360
        local currentLength = CH_Config.MinLength + (math.sin(alpha * math.pi) * (maxLen - CH_Config.MinLength))
        
        CH_Holder.Rotation = currentRotation
        CH_Top.Position = UDim2.new(0.5,0,0.5,-g); CH_Bottom.Position = UDim2.new(0.5,0,0.5,g)
        CH_Left.Position = UDim2.new(0.5,-g,0.5,0); CH_Right.Position = UDim2.new(0.5,g,0.5,0)
        local sv = UDim2.new(0, CH_Config.Thickness, 0, currentLength); CH_Top.Size = sv; CH_Bottom.Size = sv
        local sh = UDim2.new(0, currentLength, 0, CH_Config.Thickness); CH_Left.Size = sh; CH_Right.Size = sh
    else
        CH_ScreenGui.Enabled = false
        UserInputService.MouseIconEnabled = true 
    end

    if Toggles.ShowTarget.Value then
        local target = nil
        local maxStuds = Options.TargetMaxDist.Value
        for _, player in pairs(Players:GetPlayers()) do
            if player ~= LocalPlayer and player.Character and player.Character:FindFirstChild("HumanoidRootPart") then
                local myTeamName = LocalPlayer.Team and LocalPlayer.Team.Name or ""
                local tTeam = player.Team and player.Team.Name or ""
                local isEnemy = false
                if myTeamName == "Criminals" then if tTeam == "Guards" then isEnemy = true end
                elseif myTeamName == "Inmates" then if tTeam == "Guards" or tTeam == "Criminals" then isEnemy = true end
                elseif myTeamName == "Guards" then if tTeam == "Criminals" then isTarget = true end end
                if not isEnemy and tTeam == "Inmates" and player.Character.Humanoid and string.find(player.Character.Humanoid.DisplayName, "💢") then isEnemy = true end
                
                if isEnemy then
                    local root = player.Character.HumanoidRootPart
                    if (root.Position - currentCam.CFrame.Position).Magnitude <= maxStuds then
                        local vector = currentCam:WorldToViewportPoint(root.Position)
                        if vector.Z > 0 and vector.X >= -100 and vector.X <= currentCam.ViewportSize.X + 100 and vector.Y >= -100 and vector.Y <= currentCam.ViewportSize.Y + 100 then
                            if not target or (Vector2.new(vector.X, vector.Y) - mouseLoc).Magnitude < (Vector2.new(currentCam:WorldToViewportPoint(target.Character.HumanoidRootPart.Position).X, currentCam:WorldToViewportPoint(target.Character.HumanoidRootPart.Position).Y) - mouseLoc).Magnitude then
                                target = player
                            end
                        end
                    end
                end
            end
        end

        local tColor = Options.TargetColor.Value
        ST_Tracer.Color = tColor; ST_MainCircle.Color = tColor; ST_FilledCircle.Color = tColor
        ST_TracerOutline.Color = Color3.new(0,0,0); ST_OuterCircle.Color = Color3.new(0,0,0)
        
        if target and target.Character and target.Character:FindFirstChild("HumanoidRootPart") then
            local hrp = target.Character.HumanoidRootPart
            local head = target.Character:FindFirstChild("Head") or hrp
            local hrpVector = currentCam:WorldToViewportPoint(hrp.Position)
            local headVector = currentCam:WorldToViewportPoint(head.Position)
            local targetPos = Vector2.new(hrpVector.X, hrpVector.Y)
            local targetHeadPos = Vector2.new(headVector.X, headVector.Y)

            if target ~= ST_lastTarget then ST_isSwitching = true; ST_lastTarget = target end

            if ST_isSwitching then
                ST_CurrentDrawPos = ST_CurrentDrawPos:Lerp(targetPos, 0.15)
                ST_CurrentTracerTo = ST_CurrentTracerTo:Lerp(targetHeadPos, 0.15)
                if (ST_CurrentDrawPos - targetPos).Magnitude < 2 then ST_isSwitching = false end
            else
                 ST_CurrentDrawPos = targetPos; ST_CurrentTracerTo = targetHeadPos
            end

            local dist = (currentCam.CFrame.Position - hrp.Position).Magnitude
            local dynamicRadius = math.clamp((2000 / dist) * 4.5, 5, 400)

            ST_TracerOutline.From, ST_TracerOutline.To = mouseLoc, ST_CurrentTracerTo
            ST_Tracer.From, ST_Tracer.To = mouseLoc, ST_CurrentTracerTo
            ST_TracerOutline.Visible, ST_Tracer.Visible = true, true
            ST_OuterCircle.Position, ST_OuterCircle.Radius, ST_OuterCircle.Visible = ST_CurrentDrawPos, dynamicRadius, true
            ST_FilledCircle.Position, ST_FilledCircle.Radius, ST_FilledCircle.Visible = ST_CurrentDrawPos, dynamicRadius, true
            ST_MainCircle.Position, ST_MainCircle.Radius, ST_MainCircle.Visible = ST_CurrentDrawPos, dynamicRadius, true
        else
            ST_isSwitching = false; ST_lastTarget = nil
            ST_TracerOutline.Visible, ST_Tracer.Visible, ST_OuterCircle.Visible, ST_MainCircle.Visible, ST_FilledCircle.Visible = false, false, false, false, false
        end
    else
        ST_isSwitching = false; ST_lastTarget = nil
        ST_TracerOutline.Visible, ST_Tracer.Visible, ST_OuterCircle.Visible, ST_MainCircle.Visible, ST_FilledCircle.Visible = false, false, false, false, false
    end
end)

